def bubble_sort(dizi):
    dizi = dizi[:]
    n = len(dizi)
    for i in range(n):
        for j in range(0, n - i - 1):
            if dizi[j] > dizi[j + 1]:
                dizi[j], dizi[j + 1] = dizi[j + 1], dizi[j]
    return dizi

def selection_sort(dizi):
    dizi = dizi[:]
    n = len(dizi)
    for i in range(n):
        min_idx = i
        for j in range(i + 1, n):
            if dizi[j] < dizi[min_idx]:
                min_idx = j
        dizi[i], dizi[min_idx] = dizi[min_idx], dizi[i]
    return dizi

